public int numTrees(int n) {
    // Catalan number: C(2n, n) / (n+1)
    long result = 1;
    for (int i = 0; i < n; i++) {
        result = result * (2 * n - i) / (i + 1);
    }
    return (int)(result / (n + 1));
}

